arguments.file_text:
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="dropZoneRef" class="file-drop-zone @(isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in files)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    @if (entry.Error is not null)
                    {
                        <span class="error-message">@entry.Name &mdash; @entry.Error</span>
                    }
                    else
                    {
                        <span class="file-name">@entry.Name</span>
                        <span class="file-meta">@FormatSize(entry.Size) &middot; @entry.Type</span>
                    }
                </div>
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    public record FileInfo(string Name, long Size, string Type);

    private record FileEntry(string Name, long Size, string Type, string? Error);

    private const long MaxSizeBytes = 10 * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference dropZoneRef;
    private IJSObjectReference? module;
    private DotNetObjectReference<FileDropZone>? dotNetRef;
    private bool isDragOver;
    private readonly List<FileEntry> files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-6c9d74f2e5734e37b43df75103a73bef/Components/FileDropZone.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);
            await module.InvokeVoidAsync("initDropZone", dropZoneRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnDragOverChanged(bool over)
    {
        isDragOver = over;
        StateHasChanged();
        await Task.CompletedTask;
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<FileInfo> droppedFiles)
    {
        isDragOver = false;

        foreach (var f in droppedFiles)
        {
            string? error = f.Size > MaxSizeBytes
                ? $"File exceeds 10 MB limit ({FormatSize(f.Size)})"
                : null;
            files.Add(new FileEntry(f.Name, f.Size, f.Type, error));
        }

        StateHasChanged();
        await NotifyParent();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = files
            .Where(f => f.Error is null)
            .Select(f => new FileInfo(f.Name, f.Size, f.Type))
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("disposeDropZone", dropZoneRef);
            await module.DisposeAsync();
        }
        dotNetRef?.Dispose();
    }
}

const zones = new Map();

export function initDropZone(element, dotNetRef) {
    function onDragOver(e) {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
    }

    function onDragLeave(e) {
        if (!element.contains(e.relatedTarget)) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    }

    function onDrop(e) {
        e.preventDefault();
        const files = [];
        for (const file of e.dataTransfer.files) {
            files.push({ name: file.name, size: file.size, type: file.type || 'unknown' });
        }
        if (files.length > 0) {
            dotNetRef.invokeMethodAsync('OnFilesDropped', files);
        } else {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    }

    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    zones.set(element, { onDragOver, onDragLeave, onDrop });
}

export function disposeDropZone(element) {
    const handlers = zones.get(element);
    if (handlers) {
        element.removeEventListener('dragover', handlers.onDragOver);
        element.removeEventListener('dragleave', handlers.onDragLeave);
        element.removeEventListener('drop', handlers.onDrop);
        zones.delete(element);
    }
}

.file-drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    color: #6c757d;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-drop-zone p {
    margin: 0;
    font-size: 1.1rem;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    min-width: 0;
}

.file-name {
    font-weight: 500;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.file-meta {
    font-size: 0.85rem;
    color: #6c757d;
}

.error-message {
    color: #dc3545;
    font-weight: 500;
}

.btn-remove {
    border: none;
    background: none;
    color: #dc3545;
    cursor: pointer;
    font-size: 0.9rem;
    padding: 0.25rem 0.5rem;
    flex-shrink: 0;
}

.btn-remove:hover {
    text-decoration: underline;
}

